fn solve(points: Vec<Vec<i64>>) -> i64 {
    let n = points.len();
    if n < 4 {
        return 0;
    }

    let mut slope_count = std::collections::HashMap::new();
    let mut total = 0;

    for i in 0..n {
        let (x1, y1) = (points[i][0], points[i][1]);
        for j in i + 1..n {
            let (x2, y2) = (points[j][0], points[j][1]);
            let dx = x2 - x1;
            let dy = y2 - y1;

            if dx == 0 {
                // Vertical line, slope is infinity
                let key = "inf";
                *slope_count.entry(key.to_string()).or_insert(0) += 1;
            } else {
                // Calculate slope as a fraction to avoid floating point errors
                let gcd = std::cmp::min(dx.abs(), dy.abs());
                let dx_reduced = dx / gcd;
                let dy_reduced = dy / gcd;

                // Ensure consistent representation (e.g., positive denominator)
                let key = if dx_reduced < 0 {
                    format!("{}{}", dy_reduced, dx_reduced)
                } else {
                    format!("{}{}", dy_reduced, dx_reduced)
                };
                *slope_count.entry(key).or_insert(0) += 1;
            }
        }
    }

    for count in slope_count.values() {
        total += count * (count - 1) / 2;
    }

    total
}
